(function () {
  "use strict";

  window.DataQuizzes = [
    // ══════════════════════════════════════════════
    //  MODULE: HISTORY (17 questions)
    // ══════════════════════════════════════════════
    { id: 1, moduleId: "history", question: "Before coins were invented, how did ancient people exchange goods?", options: { a: "Using credit cards", b: "Through barter — trading one good directly for another", c: "By emailing each other", d: "Using paper receipts" }, correctAnswer: "b", explanation: "Barter was the earliest form of trade. People swapped items like grain for livestock directly. This system was limited because it required a 'double coincidence of wants' — both parties had to want what the other offered.", difficulty: "easy", xpReward: 10 },
    { id: 2, moduleId: "history", question: "Which ancient civilization is credited with creating the first standardized metal coins?", options: { a: "Ancient Egypt", b: "The Roman Empire", c: "The Lydians (in modern-day Turkey)", d: "The Aztec Empire" }, correctAnswer: "c", explanation: "Around 600 BCE, the Lydians created coins from electrum, a naturally occurring alloy of gold and silver. These coins had standardized weights, making trade much easier than bartering.", difficulty: "easy", xpReward: 10 },
    { id: 3, moduleId: "history", question: "Why was paper money originally invented in China?", options: { a: "Because metal coins were too heavy to carry in large quantities", b: "Because paper was more valuable than gold", c: "Because the emperor wanted to eliminate trade", d: "Because barter had just been invented" }, correctAnswer: "a", explanation: "During the Tang Dynasty (7th century), Chinese merchants found that carrying heavy coins for large transactions was impractical. Paper receipts representing deposited coins became the first paper money, called 'jiaozi'.", difficulty: "medium", xpReward: 20 },
    { id: 4, moduleId: "history", question: "What was the main purpose of the Gold Standard?", options: { a: "To make gold the only thing people could buy", b: "To back paper currency with a fixed amount of gold", c: "To prevent anyone from mining gold", d: "To make paper money more colorful" }, correctAnswer: "b", explanation: "The Gold Standard, widely adopted in the 19th century, meant each unit of paper currency could be exchanged for a fixed amount of gold. This gave people confidence in paper money because it was backed by something tangible.", difficulty: "easy", xpReward: 10 },
    { id: 5, moduleId: "history", question: "When did the United States officially abandon the Gold Standard?", options: { a: "1776", b: "1913", c: "1971", d: "2008" }, correctAnswer: "c", explanation: "President Nixon ended the Gold Standard in 1971. This meant the US dollar was no longer convertible to gold, becoming a 'fiat' currency — its value backed by government decree and people's trust rather than physical gold.", difficulty: "medium", xpReward: 20 },
    { id: 6, moduleId: "history", question: "What does 'fiat' mean in the context of money?", options: { a: "Italian sports car", b: "Money that has value because a government declares it legal tender", c: "Money made from recycled materials", d: "Coins that float on water" }, correctAnswer: "b", explanation: "'Fiat' is Latin for 'let it be done.' Fiat money has value because a government says it does and people trust it. Modern currencies like the US dollar, euro, and yen are all fiat currencies.", difficulty: "easy", xpReward: 10 },
    { id: 7, moduleId: "history", question: "What problem does inflation create for people holding cash savings?", options: { a: "Cash becomes too heavy to carry", b: "The purchasing power of their money decreases over time", c: "The government takes their savings", d: "Cash becomes illegal to own" }, correctAnswer: "b", explanation: "Inflation means prices rise over time, so the same amount of money buys fewer goods. If inflation is 3% per year, $100 today will only buy what $97 buys next year. This is one reason some people look to alternative stores of value.", difficulty: "medium", xpReward: 20 },
    { id: 8, moduleId: "history", question: "Who published the Bitcoin whitepaper and when?", options: { a: "Vitalik Buterin in 2015", b: "Satoshi Nakamoto in 2008", c: "Elon Musk in 2009", d: "Hal Finney in 2010" }, correctAnswer: "b", explanation: "Satoshi Nakamoto (a pseudonym — the real identity remains unknown) published the Bitcoin whitepaper titled 'Bitcoin: A Peer-to-Peer Electronic Cash System' on October 31, 2008. The Bitcoin network launched on January 3, 2009.", difficulty: "easy", xpReward: 10 },
    { id: 9, moduleId: "history", question: "What major financial crisis in 2008 partly inspired the creation of Bitcoin?", options: { a: "The Dot-Com Crash", b: "The Great Depression", c: "The Global Financial Crisis (housing market collapse)", d: "The European Debt Crisis" }, correctAnswer: "c", explanation: "The 2008 financial crisis, caused by subprime mortgage lending and bank failures, eroded trust in traditional financial institutions. The Bitcoin genesis block contained a newspaper headline about bank bailouts, highlighting this motivation.", difficulty: "medium", xpReward: 20 },
    { id: 10, moduleId: "history", question: "What was the first real-world purchase made with Bitcoin?", options: { a: "A house", b: "Two pizzas for 10,000 BTC", c: "A Tesla car", d: "A concert ticket" }, correctAnswer: "b", explanation: "On May 22, 2010, Laszlo Hanyecz paid 10,000 BTC for two Papa John's pizzas — worth about $41 at the time. At today's prices, those pizzas would be worth hundreds of millions of dollars. May 22 is now celebrated as 'Bitcoin Pizza Day.'", difficulty: "easy", xpReward: 10 },
    { id: 11, moduleId: "history", question: "What was the primary innovation that Bitcoin introduced?", options: { a: "Digital money (it already existed before Bitcoin)", b: "A decentralized digital currency without needing a trusted third party", c: "The concept of online shopping", d: "The first computer network" }, correctAnswer: "b", explanation: "Digital money existed before Bitcoin (think PayPal or bank transfers), but it always required a trusted middleman. Bitcoin's breakthrough was solving the 'double-spending problem' without a central authority, using blockchain technology.", difficulty: "hard", xpReward: 30 },
    { id: 12, moduleId: "history", question: "What was 'Cypherpunks' and how did they influence cryptocurrency?", options: { a: "A 1990s punk rock band", b: "A group of activists advocating for privacy through cryptography", c: "A type of computer virus", d: "A government surveillance program" }, correctAnswer: "b", explanation: "The Cypherpunks were a movement of activists and cryptographers in the 1990s who believed privacy was a fundamental right. They developed early digital cash concepts and cryptographic tools that directly influenced Bitcoin's design.", difficulty: "hard", xpReward: 30 },
    { id: 13, moduleId: "history", question: "Which was the first alternative cryptocurrency (altcoin) created after Bitcoin?", options: { a: "Ethereum", b: "Litecoin", c: "Namecoin", d: "Ripple" }, correctAnswer: "c", explanation: "Namecoin launched in April 2011, making it the first altcoin. It was based on Bitcoin's code and aimed to provide a decentralized domain name system. Litecoin followed later in 2011 as 'the silver to Bitcoin's gold.'", difficulty: "hard", xpReward: 30 },
    { id: 14, moduleId: "history", question: "What does the 'genesis block' refer to in Bitcoin's history?", options: { a: "The first block ever mined on the Bitcoin blockchain", b: "A special type of cryptocurrency", c: "The last Bitcoin that will ever be mined", d: "A mining hardware brand" }, correctAnswer: "a", explanation: "The genesis block is the very first block in the Bitcoin blockchain, mined by Satoshi Nakamoto on January 3, 2009. It contained a hidden message: a newspaper headline about bank bailouts, showing Bitcoin's purpose.", difficulty: "medium", xpReward: 20 },
    { id: 15, moduleId: "history", question: "Why did the invention of credit cards in the 1950s matter for the history of money?", options: { a: "It was the first time people could buy things", b: "It introduced the concept of buying now and paying later using a trusted network", c: "It replaced all paper money instantly", d: "It was invented by a cryptocurrency founder" }, correctAnswer: "b", explanation: "The Diners Club card (1950) and later Visa and Mastercard introduced electronic payment networks. These centralized systems trusted banks to verify transactions — exactly the model that Bitcoin would later challenge with decentralization.", difficulty: "medium", xpReward: 20 },
    { id: 16, moduleId: "history", question: "What was the 'double-spending problem' that Bitcoin solved?", options: { a: "Spending money twice at the same store", b: "The risk of spending the same digital unit more than once in a digital system", c: "Losing money twice in the same day", d: "Two people trying to mine the same coin" }, correctAnswer: "b", explanation: "In digital systems, it's easy to copy a file — so how do you prevent someone from spending the same digital coin twice? Before Bitcoin, this required a trusted bank. Bitcoin solved it using the blockchain and proof-of-work consensus.", difficulty: "hard", xpReward: 30 },
    { id: 17, moduleId: "history", question: "How did the invention of the internet change money?", options: { a: "It made physical coins obsolete immediately", b: "It enabled electronic money transfers and online banking", c: "It had no effect on money at all", d: "It made all money digital instantly" }, correctAnswer: "b", explanation: "The internet revolutionized money by enabling instant electronic transfers, online banking, and digital payment systems. While traditional money remained, the infrastructure for digital currencies was built, paving the way for cryptocurrency.", difficulty: "easy", xpReward: 10 },

    // ══════════════════════════════════════════════
    //  MODULE: BLOCKCHAIN (17 questions)
    // ══════════════════════════════════════════════
    { id: 18, moduleId: "blockchain", question: "What is a blockchain?", options: { a: "A chain made of blocks of gold", b: "A digital, decentralized ledger that records transactions across many computers", c: "A type of computer hardware", d: "A social media platform" }, correctAnswer: "b", explanation: "A blockchain is a chain of digital 'blocks,' each containing a batch of transactions. It's maintained by a network of computers (nodes) rather than a single authority, making it decentralized and tamper-resistant.", difficulty: "easy", xpReward: 10 },
    { id: 19, moduleId: "blockchain", question: "What is a 'block' in the blockchain?", options: { a: "A physical cube stored in a vault", b: "A group of transactions bundled together with a cryptographic hash", c: "A unit of cryptocurrency", d: "A type of computer memory" }, correctAnswer: "b", explanation: "Each block contains a list of verified transactions, a timestamp, and a cryptographic hash linking it to the previous block. Think of it as a page in a shared notebook — once a page is written and sealed, it can't be erased.", difficulty: "easy", xpReward: 10 },
    { id: 20, moduleId: "blockchain", question: "What is a cryptographic hash function?", options: { a: "A cooking recipe for encryption", b: "A mathematical function that converts data into a fixed-length string of characters", c: "A type of password", d: "A hardware device for mining" }, correctAnswer: "b", explanation: "A hash function takes any input and produces a fixed-length output (like a digital fingerprint). Even a tiny change in input creates a completely different hash. Bitcoin uses SHA-256, which always produces a 64-character hexadecimal output.", difficulty: "medium", xpReward: 20 },
    { id: 21, moduleId: "blockchain", question: "What makes a blockchain 'immutable'?", options: { a: "It can never be read", b: "Once data is recorded, it's extremely difficult to alter without detection", c: "It is stored on paper", d: "Only governments can change it" }, correctAnswer: "b", explanation: "Immutability comes from how blocks are linked. Each block contains the hash of the previous block. If someone changes data in an old block, its hash changes, breaking the chain. Changing one block would require changing all subsequent blocks — nearly impossible on a large network.", difficulty: "medium", xpReward: 20 },
    { id: 22, moduleId: "blockchain", question: "What is a 'node' in a blockchain network?", options: { a: "A type of cryptocurrency wallet", b: "A computer that maintains a copy of the blockchain and validates transactions", c: "A mining pool", d: "A website for trading crypto" }, correctAnswer: "b", explanation: "Nodes are computers running blockchain software that store a copy of the entire (or partial) blockchain. They verify transactions and blocks according to the network's rules. More nodes means more decentralization and security.", difficulty: "easy", xpReward: 10 },
    { id: 23, moduleId: "blockchain", question: "What is a 'consensus mechanism'?", options: { a: "A voting system for electing blockchain leaders", b: "A method for nodes in a network to agree on the current state of the blockchain", c: "A type of cryptocurrency exchange", d: "A government regulation for crypto" }, correctAnswer: "b", explanation: "Consensus mechanisms ensure all nodes agree on which transactions are valid and in what order they occurred. Popular mechanisms include Proof of Work (used by Bitcoin) and Proof of Stake (used by Ethereum).", difficulty: "medium", xpReward: 20 },
    { id: 24, moduleId: "blockchain", question: "How does Proof of Work (PoW) secure the blockchain?", options: { a: "Miners prove they have a job", b: "Miners compete to solve complex math puzzles; solving proves they expended computational effort", c: "The government verifies all transactions", d: "Users vote on each transaction" }, correctAnswer: "b", explanation: "In PoW, miners use powerful computers to find a hash below a target value, which requires massive computational work. This makes attacking the blockchain prohibitively expensive — an attacker would need to out-compute the entire honest network.", difficulty: "medium", xpReward: 20 },
    { id: 25, moduleId: "blockchain", question: "What is the main advantage of decentralization in blockchain?", options: { a: "Faster transactions than any other system", b: "No single point of failure and no need to trust a central authority", c: "It uses less electricity", d: "It is easier to regulate" }, correctAnswer: "b", explanation: "Decentralization means no single entity controls the network. If one node goes down, thousands of others keep the network running. There's also no CEO or company that can be pressured, hacked, or corrupted to change the rules.", difficulty: "medium", xpReward: 20 },
    { id: 26, moduleId: "blockchain", question: "What is a 'smart contract'?", options: { a: "A legally binding document signed by a lawyer", b: "Self-executing code on the blockchain that automatically enforces agreed-upon rules", c: "A contract between two miners", d: "A subscription service for crypto news" }, correctAnswer: "b", explanation: "Smart contracts are programs stored on the blockchain that automatically execute when predefined conditions are met. For example, a smart contract could automatically send payment when a package delivery is confirmed — no intermediary needed.", difficulty: "medium", xpReward: 20 },
    { id: 27, moduleId: "blockchain", question: "What does 'public key cryptography' enable in cryptocurrency?", options: { a: "Everyone can see your password", b: "Secure ownership and transfer of digital assets using key pairs", c: "Faster internet connections", d: "Government surveillance of transactions" }, correctAnswer: "b", explanation: "Each user has a public key (like an account number — safe to share) and a private key (like a password — must be kept secret). You can receive funds with your public key and spend them by signing transactions with your private key.", difficulty: "medium", xpReward: 20 },
    { id: 28, moduleId: "blockchain", question: "What happens if someone tries to tamper with a block in the middle of the blockchain?", options: { a: "Nothing — nobody would notice", b: "The hash of that block changes, breaking the chain and alerting all nodes", c: "The blockchain automatically deletes the tampered block", d: "The tampered block becomes the new truth" }, correctAnswer: "b", explanation: "Each block's hash depends on its data AND the previous block's hash. Changing even one transaction changes the block's hash, which breaks the link to the next block. Every subsequent block would need to be recalculated, which is computationally impossible for a large network.", difficulty: "hard", xpReward: 30 },
    { id: 29, moduleId: "blockchain", question: "What is a '51% attack'?", options: { a: "When 51% of users complain about a blockchain", b: "When one entity controls more than half the network's mining power, potentially allowing them to manipulate transactions", c: "When a blockchain splits into two", d: "When 51% of coins are lost" }, correctAnswer: "b", explanation: "If an attacker controls 51%+ of a PoW network's hash rate, they could potentially reverse transactions or double-spend coins. However, this would be extremely expensive and would likely crash the coin's value, making it self-defeating.", difficulty: "hard", xpReward: 30 },
    { id: 30, moduleId: "blockchain", question: "What is the difference between a public and private blockchain?", options: { a: "Public blockchains are slower; private ones are free", b: "Public blockchains are open to anyone; private blockchains restrict access to approved participants", c: "There is no difference", d: "Public blockchains are illegal" }, correctAnswer: "b", explanation: "Public (permissionless) blockchains like Bitcoin allow anyone to participate, read, and write data. Private (permissioned) blockchains restrict who can validate transactions and are often used by businesses for internal purposes.", difficulty: "easy", xpReward: 10 },
    { id: 31, moduleId: "blockchain", question: "What is a 'fork' in blockchain terms?", options: { a: "A utensil used by miners", b: "A split in the blockchain's protocol, creating two separate versions", c: "A way to speed up transactions", d: "A type of wallet" }, correctAnswer: "b", explanation: "A fork happens when a blockchain's protocol is updated or changed. 'Soft forks' are backward-compatible; 'hard forks' create a permanently split chain. Bitcoin Cash was created through a hard fork of Bitcoin in 2017.", difficulty: "medium", xpReward: 20 },
    { id: 32, moduleId: "blockchain", question: "Why is blockchain often described as a 'trustless' system?", options: { a: "Because nobody should ever use it", b: "Because you don't need to trust any single party — the system's math and code ensure correctness", c: "Because it is unregulated", d: "Because all users are anonymous" }, correctAnswer: "b", explanation: "'Trustless' doesn't mean untrustworthy — it means you don't need to trust any individual or institution. Instead, you trust the cryptography, the consensus rules, and the economic incentives built into the protocol.", difficulty: "hard", xpReward: 30 },
    { id: 33, moduleId: "blockchain", question: "What is 'scalability' and why is it a challenge for blockchains?", options: { a: "The ability to grow larger in physical size", b: "The ability to handle more transactions per second — a challenge because each block has limited space", c: "The ability to support more types of cryptocurrency", d: "The ability to make blocks heavier" }, correctAnswer: "b", explanation: "Visa can process ~65,000 transactions per second, while Bitcoin handles ~7 and Ethereum ~15. Scalability solutions like Layer 2 networks and sharding aim to increase throughput without sacrificing security or decentralization.", difficulty: "hard", xpReward: 30 },
    { id: 34, moduleId: "blockchain", question: "What is a Layer 2 solution?", options: { a: "A second blockchain that completely replaces the main one", b: "A network built on top of a main blockchain to process transactions faster and cheaper", c: "A backup copy of the blockchain", d: "A new type of mining hardware" }, correctAnswer: "b", explanation: "Layer 2 solutions like the Lightning Network (for Bitcoin) and rollups (for Ethereum) handle transactions off the main chain, then settle batches on the main chain. This dramatically increases speed and reduces fees while inheriting the security of the underlying blockchain.", difficulty: "hard", xpReward: 30 },

    // ══════════════════════════════════════════════
    //  MODULE: BITCOIN (17 questions)
    // ══════════════════════════════════════════════
    { id: 35, moduleId: "bitcoin", question: "What is Bitcoin mining?", options: { a: "Digging physical coins out of the ground", b: "Using computers to solve complex mathematical puzzles to validate transactions and create new bitcoins", c: "Buying Bitcoin from an exchange", d: "Printing paper Bitcoin certificates" }, correctAnswer: "b", explanation: "Bitcoin miners use specialized computers to find a valid hash for each new block. This process secures the network, verifies transactions, and releases new bitcoins as a reward. It's called 'mining' by analogy to gold mining.", difficulty: "easy", xpReward: 10 },
    { id: 36, moduleId: "bitcoin", question: "What is the maximum supply of Bitcoin?", options: { a: "There is no limit", b: "21 million BTC", c: "100 million BTC", d: "1 billion BTC" }, correctAnswer: "b", explanation: "Bitcoin's code enforces a hard cap of 21 million coins. As of now, over 19.5 million have been mined. This scarcity is a fundamental feature — unlike fiat currencies, no government or central bank can 'print more' Bitcoin.", difficulty: "easy", xpReward: 10 },
    { id: 37, moduleId: "bitcoin", question: "What is the 'halving' in Bitcoin?", options: { a: "When the price of Bitcoin is cut in half", b: "When the block reward for miners is reduced by 50%, occurring approximately every 4 years", c: "When Bitcoin splits into two coins", d: "When mining difficulty is halved" }, correctAnswer: "b", explanation: "Approximately every 210,000 blocks (about 4 years), the block reward halves. It started at 50 BTC in 2009, then 25 in 2012, 12.5 in 2016, 6.25 in 2020, and 3.125 in 2024. This reduces the rate of new supply entering the market.", difficulty: "medium", xpReward: 20 },
    { id: 38, moduleId: "bitcoin", question: "How does Bitcoin's difficulty adjustment work?", options: { a: "Miners vote on how hard mining should be", b: "The network automatically adjusts mining difficulty every 2016 blocks to maintain ~10-minute block times", c: "The government sets the difficulty level", d: "Difficulty never changes" }, correctAnswer: "b", explanation: "If more miners join, blocks are found faster. Every 2016 blocks (~2 weeks), the network adjusts difficulty to keep the average block time near 10 minutes. If blocks are being found too quickly, difficulty increases; if too slowly, it decreases.", difficulty: "medium", xpReward: 20 },
    { id: 39, moduleId: "bitcoin", question: "What is a Bitcoin wallet address?", options: { a: "A physical location where you store Bitcoin", b: "A string of alphanumeric characters derived from your public key, used to receive Bitcoin", c: "Your email address linked to Bitcoin", d: "A bank account number" }, correctAnswer: "b", explanation: "A Bitcoin address (like 1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa) is derived from your public key through hashing. You can share it freely to receive payments, but only you can spend from it using your private key.", difficulty: "easy", xpReward: 10 },
    { id: 40, moduleId: "bitcoin", question: "What is a 'private key' and why is it so important?", options: { a: "A key that locks your physical door", b: "A secret number that proves ownership of your Bitcoin and allows you to spend it", c: "A password for your email", d: "A public piece of information" }, correctAnswer: "b", explanation: "Your private key is essentially your Bitcoin password — anyone who has it can spend your Bitcoin. It should NEVER be shared. If you lose your private key and have no backup, your Bitcoin is permanently inaccessible.", difficulty: "easy", xpReward: 10 },
    { id: 41, moduleId: "bitcoin", question: "What is the Lightning Network?", options: { a: "A new type of Bitcoin mining hardware", b: "A Layer 2 payment protocol built on top of Bitcoin for fast, cheap transactions", c: "A Bitcoin exchange", d: "A weather monitoring network" }, correctAnswer: "b", explanation: "The Lightning Network allows users to open payment channels between each other for near-instant, extremely cheap transactions. These happen off-chain, and only the opening and closing transactions are recorded on the Bitcoin blockchain.", difficulty: "medium", xpReward: 20 },
    { id: 42, moduleId: "bitcoin", question: "Why are Bitcoin transactions irreversible?", options: { a: "Because the government says so", b: "Because once a transaction is confirmed in a block, it becomes part of the permanent blockchain record", c: "Because exchanges don't allow refunds", d: "Because Bitcoin is not real money" }, correctAnswer: "b", explanation: "Unlike credit card payments, Bitcoin transactions cannot be reversed by any party. Once confirmed in a block, the transaction is permanently recorded. This is a feature, not a bug — it eliminates the risk of chargeback fraud.", difficulty: "medium", xpReward: 20 },
    { id: 43, moduleId: "bitcoin", question: "What is a 'seed phrase' (recovery phrase)?", options: { a: "A phrase you say to start mining", b: "12 or 24 words that can restore all your wallets and funds if you lose access", c: "A secret password for exchanges", d: "A marketing slogan for Bitcoin" }, correctAnswer: "b", explanation: "A seed phrase is a human-readable backup of your wallet's private keys. If your wallet is lost, stolen, or damaged, you can enter these words into any compatible wallet to recover your funds. Store it securely offline!", difficulty: "easy", xpReward: 10 },
    { id: 44, moduleId: "bitcoin", question: "What is a UTXO?", options: { a: "An exchange where you trade Bitcoin", b: "An Unspent Transaction Output — a chunk of Bitcoin waiting to be spent", c: "A type of Bitcoin wallet", d: "A mining pool" }, correctAnswer: "b", explanation: "Bitcoin uses a UTXO model. When you receive Bitcoin, it's recorded as a UTXO assigned to your address. When you spend, UTXOs are consumed and new ones are created. Your 'balance' is the sum of all UTXOs you control.", difficulty: "hard", xpReward: 30 },
    { id: 45, moduleId: "bitcoin", question: "How much energy does Bitcoin mining approximately consume?", options: { a: "Almost zero", b: "Roughly equivalent to a small country's electricity usage", c: "More than the entire world's energy", d: "Less than a single household" }, correctAnswer: "b", explanation: "Bitcoin mining consumes significant electricity — comparable to countries like Argentina or Norway. This is because the proof-of-work algorithm requires enormous computational effort. However, an increasing percentage comes from renewable sources.", difficulty: "medium", xpReward: 20 },
    { id: 46, moduleId: "bitcoin", question: "What happens to Bitcoin mining rewards after all 21 million BTC are mined?", options: { a: "Mining stops and the network shuts down", b: "Miners will only earn from transaction fees, not block rewards", c: "The cap is removed and more Bitcoin is created", d: "The government takes over mining" }, correctAnswer: "b", explanation: "After the last Bitcoin is mined (estimated around 2140), miners will still be needed to process transactions and secure the network. They'll be compensated entirely by transaction fees rather than newly created coins.", difficulty: "hard", xpReward: 30 },
    { id: 47, moduleId: "bitcoin", question: "What is a 'cold wallet' (cold storage)?", options: { a: "A wallet kept in a refrigerator", b: "A wallet that stores private keys offline, away from internet access", c: "A wallet that only holds frozen assets", d: "An exchange wallet" }, correctAnswer: "b", explanation: "Cold storage keeps private keys completely offline, making them immune to online hacking. Hardware wallets (like Ledger or Trezor), paper wallets, and even engraved metal plates are common cold storage methods. 'Hot wallets' are connected to the internet.", difficulty: "easy", xpReward: 10 },
    { id: 48, moduleId: "bitcoin", question: "What is a 'confirmation' in Bitcoin?", options: { a: "A phone call from your bank", b: "When a transaction is included in a block and subsequent blocks are added after it", c: "When an exchange approves your purchase", d: "An email from Bitcoin" }, correctAnswer: "b", explanation: "A transaction is 'confirmed' when it's included in a block. Each additional block added on top increases the confirmation count. Six confirmations is considered very secure because it would require enormous computational power to reverse.", difficulty: "medium", xpReward: 20 },
    { id: 49, moduleId: "bitcoin", question: "What is the difference between Bitcoin the protocol and bitcoin the currency?", options: { a: "There is no difference", b: "Bitcoin (capital B) is the network/protocol; bitcoin (lowercase b) is the currency unit", c: "Bitcoin is digital and bitcoin is physical", d: "Bitcoin is for buying and bitcoin is for selling" }, correctAnswer: "b", explanation: "Bitcoin (with a capital B) refers to the entire protocol, network, and technology. bitcoin (lowercase b) or BTC refers to the actual currency/token. Think of it like 'the Internet' vs. 'an internet connection.'", difficulty: "medium", xpReward: 20 },
    { id: 50, moduleId: "bitcoin", question: "Why can't someone just copy a Bitcoin transaction to 'double spend'?", options: { a: "Because computers can't copy data", b: "Because the network's nodes and consensus mechanism would reject the duplicate", c: "Because Bitcoin is physical", d: "Because exchanges prevent it" }, correctAnswer: "b", explanation: "When you broadcast a transaction, all nodes verify you actually own the Bitcoin being spent. Once a transaction is confirmed in a block, any attempt to spend the same UTXO again is rejected by the network. This is the core innovation of blockchain.", difficulty: "hard", xpReward: 30 },
    { id: 51, moduleId: "bitcoin", question: "What is the average block time for Bitcoin?", options: { a: "1 second", b: "10 minutes", c: "1 hour", d: "24 hours" }, correctAnswer: "b", explanation: "Bitcoin is designed to produce one block approximately every 10 minutes. The difficulty adjustment mechanism ensures this average is maintained regardless of how many miners are participating or how powerful their equipment is.", difficulty: "easy", xpReward: 10 },

    // ══════════════════════════════════════════════
    //  MODULE: TRADING (17 questions)
    // ══════════════════════════════════════════════
    { id: 52, moduleId: "trading", question: "What is a cryptocurrency exchange?", options: { a: "A place where people trade physical coins face-to-face", b: "A digital platform where users can buy, sell, and trade cryptocurrencies", c: "A government office for crypto registration", d: "A type of Bitcoin wallet" }, correctAnswer: "b", explanation: "Crypto exchanges like Binance, Coinbase, and Kraken are online platforms that match buyers and sellers. They provide price charts, order books, and trading tools. Always research an exchange's reputation and security before using it.", difficulty: "easy", xpReward: 10 },
    { id: 53, moduleId: "trading", question: "What is the difference between a market order and a limit order?", options: { a: "They are the same thing", b: "A market order buys/sells immediately at the current price; a limit order only executes at your specified price", c: "A market order is for stocks and a limit order is for crypto", d: "A limit order is faster than a market order" }, correctAnswer: "b", explanation: "Market orders execute immediately at the best available price — fast but you might not get the exact price you see. Limit orders let you set a specific price — they only execute if the market reaches that price, giving you more control.", difficulty: "easy", xpReward: 10 },
    { id: 54, moduleId: "trading", question: "What does 'market cap' (market capitalization) mean in crypto?", options: { a: "The maximum price a coin can reach", b: "The total value of all coins in circulation: current price × total supply", c: "A limit on how much you can trade", d: "The number of exchanges listing a coin" }, correctAnswer: "b", explanation: "Market cap = current price × circulating supply. It shows the total value of a cryptocurrency. For example, if Bitcoin is $68,000 and 19.5 million BTC exist, its market cap is roughly $1.3 trillion.", difficulty: "easy", xpReward: 10 },
    { id: 55, moduleId: "trading", question: "What is a 'candlestick chart'?", options: { a: "A chart showing candle manufacturing statistics", b: "A financial chart that shows price movements using candle-shaped symbols showing open, high, low, and close prices", c: "A chart that only shows closing prices", d: "A type of pie chart" }, correctAnswer: "b", explanation: "Each candlestick shows four prices for a time period: open (start), close (end), high (peak), and low (trough). Green/white candles mean the price went up; red/black mean it went down. Candlestick patterns help traders identify trends and potential reversals.", difficulty: "medium", xpReward: 20 },
    { id: 56, moduleId: "trading", question: "What does 'FUD' stand for in crypto trading?", options: { a: "Fast Underlying Data", b: "Fear, Uncertainty, and Doubt — negative sentiment that can drive prices down", c: "Future Unified Development", d: "Free Unlimited Deposits" }, correctAnswer: "b", explanation: "FUD refers to spreading fear, uncertainty, and doubt about a cryptocurrency, often to manipulate prices downward. An example would be spreading unverified rumors about a hack. Smart investors try to evaluate facts rather than react to FUD.", difficulty: "medium", xpReward: 20 },
    { id: 57, moduleId: "trading", question: "What is 'FOMO' in trading?", options: { a: "Fear Of Missing Out — buying impulsively because a price is rising rapidly", b: "Fast Order Market Operations", c: "Free Online Money Offers", d: "Future Of Market Operations" }, correctAnswer: "a", explanation: "FOMO happens when you see a coin's price skyrocketing and buy in hastily, fearing you'll miss the gains. This often leads to buying at the peak. Good traders make decisions based on research and strategy, not emotions.", difficulty: "easy", xpReward: 10 },
    { id: 58, moduleId: "trading", question: "What is a 'stop-loss order'?", options: { a: "An order to stop trading permanently", b: "An order that automatically sells an asset when it falls to a specified price to limit losses", c: "An order that only buys at the lowest price", d: "An order to stop the market from crashing" }, correctAnswer: "b", explanation: "A stop-loss is a risk management tool. For example, if you buy Bitcoin at $65,000, you might set a stop-loss at $60,000. If the price drops to $60,000, your Bitcoin is automatically sold, limiting your loss to about 7.7%.", difficulty: "medium", xpReward: 20 },
    { id: 59, moduleId: "trading", question: "What is 'trading volume' and why does it matter?", options: { a: "How loud the trading floor is", b: "The total number of coins/units traded in a given period — high volume indicates strong interest", c: "The number of exchanges a coin is listed on", d: "The physical size of a cryptocurrency" }, correctAnswer: "b", explanation: "Volume shows how much of an asset was traded. A price move with high volume is more 'legitimate' and likely to continue. A price move on low volume might be unreliable. Traders often compare volume patterns with price patterns.", difficulty: "medium", xpReward: 20 },
    { id: 60, moduleId: "trading", question: "What is 'liquidity' in crypto markets?", options: { a: "How much water is used in mining", b: "How easily an asset can be bought or sold without significantly affecting its price", c: "The number of coins available to mine", d: "A measure of how popular a coin is on social media" }, correctAnswer: "b", explanation: "High liquidity means there are many buyers and sellers, so large orders don't cause big price swings. Bitcoin has high liquidity. A small, obscure coin might have low liquidity, meaning selling even a small amount could crash its price.", difficulty: "medium", xpReward: 20 },
    { id: 61, moduleId: "trading", question: "What does 'HODL' mean?", options: { a: "Hold On, Don't Leave", b: "A misspelling of 'hold' that became a crypto slang term for holding onto your coins long-term", c: "High Order Digital Ledger", d: "Heavy Operations Done Locally" }, correctAnswer: "b", explanation: "'HODL' originated from a 2013 forum post titled 'I AM HODLING' where a user misspelled 'holding' during a market crash. It's now a widely used term meaning to hold your crypto through price volatility rather than selling.", difficulty: "easy", xpReward: 10 },
    { id: 62, moduleId: "trading", question: "What is a 'bear market' in crypto?", options: { a: "A market where bears are trading", b: "A prolonged period of declining prices, typically defined as a drop of 20% or more from recent highs", c: "A market that only operates during winter", d: "A market with no trading activity" }, correctAnswer: "b", explanation: "A bear market is characterized by falling prices and pessimism. In crypto, bear markets can be severe — Bitcoin has experienced multiple 70%+ drawdowns. Bull markets are the opposite, with rising prices and optimism.", difficulty: "easy", xpReward: 10 },
    { id: 63, moduleId: "trading", question: "What is 'leverage' in cryptocurrency trading?", options: { a: "A type of cryptocurrency", b: "Borrowing money to multiply your trading position — amplifying both potential gains AND losses", c: "A strategy of buying only one coin", d: "A way to trade without risk" }, correctAnswer: "b", explanation: "Leverage lets you control a larger position with less capital. 10x leverage means a 10% price move in your favor gives 100% profit — but a 10% move against you wipes out your entire position. Beginners should avoid high leverage.", difficulty: "medium", xpReward: 20 },
    { id: 64, moduleId: "trading", question: "What is a 'bull run'?", options: { a: "When bulls start trading cryptocurrency", b: "A sustained period of rising cryptocurrency prices and market optimism", c: "A trading competition", d: "A type of market manipulation" }, correctAnswer: "b", explanation: "A bull run is an extended period where prices rise significantly. Crypto bull runs have historically produced enormous returns, but they're always followed by bear market corrections. Understanding market cycles helps avoid buying at the peak.", difficulty: "easy", xpReward: 10 },
    { id: 65, moduleId: "trading", question: "What is 'dollar-cost averaging' (DCA)?", options: { a: "Converting all your dollars to crypto at once", b: "Investing a fixed amount at regular intervals regardless of price, reducing the impact of volatility", c: "Only buying when the dollar is strong", d: "Averaging the prices of all cryptocurrencies" }, correctAnswer: "b", explanation: "Instead of trying to time the market, DCA involves buying, say, $50 every week. You buy more crypto when prices are low and less when they're high, naturally averaging your purchase price over time. This reduces stress and the risk of buying at a peak.", difficulty: "medium", xpReward: 20 },
    { id: 66, moduleId: "trading", question: "What is a 'spread' in trading?", options: { a: "The distance between two exchanges", b: "The difference between the buy (ask) price and the sell (bid) price of an asset", c: "A type of trading strategy", d: "The total number of trades in a day" }, correctAnswer: "b", explanation: "The spread is the gap between what buyers will pay (bid) and what sellers are asking (ask). Tighter spreads (smaller differences) indicate a more liquid and efficient market. The spread is effectively a cost that traders pay.", difficulty: "medium", xpReward: 20 },
    { id: 67, moduleId: "trading", question: "What is a 'whale' in crypto trading?", options: { a: "A cryptocurrency that lives in the ocean", b: "An individual or entity that holds a very large amount of a cryptocurrency", c: "A type of trading bot", d: "A new cryptocurrency project" }, correctAnswer: "b", explanation: "Whales hold enough cryptocurrency to influence market prices when they buy or sell. For example, Satoshi Nakamoto is believed to hold ~1 million BTC, making them the biggest whale. Whale movements are closely watched by traders.", difficulty: "easy", xpReward: 10 },
    { id: 68, moduleId: "trading", question: "Why is 'paper trading' recommended for beginners?", options: { a: "Because it uses actual paper money", b: "It allows you to practice trading strategies with simulated money, without financial risk", c: "Because it's required by law", d: "Because real trading doesn't work" }, correctAnswer: "b", explanation: "Paper trading lets you test strategies, learn to read charts, and understand market dynamics without risking real money. Many exchanges offer demo accounts. It's the crypto equivalent of a driving simulator before getting on the road.", difficulty: "easy", xpReward: 10 },

    // ══════════════════════════════════════════════
    //  MODULE: SCAMS (17 questions)
    // ══════════════════════════════════════════════
    { id: 69, moduleId: "scams", question: "What is a 'rug pull' in cryptocurrency?", options: { a: "Removing a rug from a marketplace", b: "When developers suddenly abandon a project and drain all the invested funds", c: "A type of mining technique", d: "When a coin's price naturally drops" }, correctAnswer: "b", explanation: "In a rug pull, creators hype a project, attract investors, then suddenly withdraw all liquidity and disappear. It's named after 'pulling the rug out' from under investors. Warning signs include anonymous teams, unaudited contracts, and unrealistic promises.", difficulty: "easy", xpReward: 10 },
    { id: 70, moduleId: "scams", question: "What is a 'pump and dump' scheme?", options: { a: "Inflating and then releasing a physical pump", b: "Coordinated buying to inflate a price, then selling at the peak to profit at the expense of late buyers", c: "A legitimate trading strategy", d: "A way to increase mining efficiency" }, correctAnswer: "b", explanation: "Scammers buy a low-value coin, then use social media, hype, and coordinated buying to drive the price up. Once the price peaks, they sell their holdings at a profit, causing the price to crash. Those who bought late lose money.", difficulty: "easy", xpReward: 10 },
    { id: 71, moduleId: "scams", question: "How do fake crypto giveaway scams typically work?", options: { a: "They actually send you free crypto", b: "They promise to double or multiply your crypto if you send them funds first", c: "They ask you to fill out a survey", d: "They give you a discount code" }, correctAnswer: "b", explanation: "These scams often impersonate celebrities or exchanges on social media, claiming 'send 1 BTC and receive 2 BTC back!' The 'guaranteed returns' never come. Legitimate projects never ask you to send crypto to receive more.", difficulty: "easy", xpReward: 10 },
    { id: 72, moduleId: "scams", question: "What is a phishing attack in the context of cryptocurrency?", options: { a: "When real fish try to steal your crypto", b: "When scammers create fake websites or emails that look legitimate to steal your private keys or passwords", c: "A type of computer virus", d: "A way to recover lost passwords" }, correctAnswer: "b", explanation: "Phishing scams create convincing copies of exchange login pages, wallet interfaces, or official emails. When you enter your credentials, the scammers capture them and immediately drain your accounts. Always verify URLs and never click suspicious links.", difficulty: "easy", xpReward: 10 },
    { id: 73, moduleId: "scams", question: "What is a 'honey pot' token scam?", options: { a: "A token that produces honey", b: "A token you can buy but cannot sell — the smart contract prevents selling", c: "A very sweet-tasting investment", d: "A legitimate savings account" }, correctAnswer: "b", explanation: "Honeypot tokens have malicious smart contracts that let you buy in but block you from selling. The scammers profit from everyone who buys in, thinking they're making a great investment. Always check if a token's contract has been audited.", difficulty: "medium", xpReward: 20 },
    { id: 74, moduleId: "scams", question: "What is a red flag that a crypto project might be a scam?", options: { a: "The project has a clear whitepaper", b: "The team promises guaranteed high returns with no risk", c: "The project is listed on major exchanges", d: "The team has verified public identities" }, correctAnswer: "b", explanation: "Any investment that promises guaranteed returns is a major red flag. All investments carry risk, especially in crypto. Legitimate projects are transparent about risks. Scammers prey on people's desire for easy money with unrealistic promises.", difficulty: "easy", xpReward: 10 },
    { id: 75, moduleId: "scams", question: "Why should you be suspicious of unsolicited direct messages about crypto?", options: { a: "Because nobody uses direct messages", b: "Scammers frequently use DMs to impersonate support staff or promote fraudulent schemes", c: "Because all DMs are from robots", d: "Because direct messages don't work" }, correctAnswer: "b", explanation: "Scammers create fake accounts impersonating exchange support, project founders, or celebrities. They DM you about 'account issues,' 'special investment opportunities,' or 'giveaways.' Legitimate support teams rarely DM first — always go directly to official channels.", difficulty: "easy", xpReward: 10 },
    { id: 76, moduleId: "scams", question: "What is 'social engineering' in crypto scams?", options: { a: "Using social media to study engineering", b: "Manipulating people psychologically to trick them into giving up private information or funds", c: "Building social networks for crypto", d: "A type of blockchain consensus" }, correctAnswer: "b", explanation: "Social engineering exploits human psychology rather than technical vulnerabilities. Examples include creating urgency ('act now or lose your funds'), authority (impersonating officials), or trust (pretending to be a friend in need).", difficulty: "medium", xpReward: 20 },
    { id: 77, moduleId: "scams", question: "What is a ' Ponzi scheme' in the crypto world?", options: { a: "A legitimate mining pool", b: "A scheme that pays returns to earlier investors using funds from newer investors rather than actual profits", c: "A type of stablecoin", d: "A government-backed crypto program" }, correctAnswer: "b", explanation: "Named after Charles Ponzi, these schemes promise high returns with little risk. Early investors get paid from new investor money, creating the illusion of a profitable business. When new money stops flowing in, the scheme collapses and most participants lose everything.", difficulty: "medium", xpReward: 20 },
    { id: 78, moduleId: "scams", question: "What should you do before investing in any crypto project?", options: { a: "Invest immediately so you don't miss out", b: "Research the team, read the whitepaper, check for audits, and verify community sentiment", c: "Only read social media posts about it", d: "Trust the first person who tells you about it" }, correctAnswer: "b", explanation: "DYOR (Do Your Own Research) is the golden rule of crypto investing. Check who's behind the project, whether the whitepaper makes sense, if the code has been audited by reputable firms, and what the broader community thinks.", difficulty: "easy", xpReward: 10 },
    { id: 79, moduleId: "scams", question: "What is 'clipboard hijacking' malware?", options: { a: "A harmless clipboard extension", b: "Malware that monitors your clipboard and replaces copied wallet addresses with the scammer's address", c: "A feature of hardware wallets", d: "A way to copy faster" }, correctAnswer: "b", explanation: "This malware runs silently on your computer. When you copy a legitimate wallet address to send funds, the malware swaps it with the scammer's address. You think you're sending to the right place, but your funds go to the attacker.", difficulty: "medium", xpReward: 20 },
    { id: 80, moduleId: "scams", question: "How can you protect yourself from crypto phishing?", options: { a: "By sharing your password with support", b: "Always verify website URLs, use bookmarks for important sites, enable 2FA, and never click suspicious links", c: "By using the same password everywhere", d: "By only using public WiFi for crypto transactions" }, correctAnswer: "b", explanation: "Key defenses: bookmark official sites and use those instead of clicking links, double-check URLs for subtle misspellings, enable two-factor authentication, use a hardware wallet for large holdings, and never share private keys with anyone.", difficulty: "medium", xpReward: 20 },
    { id: 81, moduleId: "scams", question: "What is a 'fake airdrop' scam?", options: { a: "When a real project distributes free tokens", b: "Scammers claim you've received free tokens but require you to connect your wallet to a malicious site to claim them", c: "When an exchange drops your account", d: "A type of hardware malfunction" }, correctAnswer: "b", explanation: "Real airdrops do exist — projects sometimes give free tokens to early users. Scammers send fake airdrop notifications with links to phishing sites. When you connect your wallet to 'claim' the tokens, a malicious smart contract drains your real funds.", difficulty: "medium", xpReward: 20 },
    { id: 82, moduleId: "scams", question: "Why is it dangerous to share your seed phrase with anyone?", options: { a: "Because it's not useful to anyone", b: "Your seed phrase gives complete access to your wallet — anyone with it can steal all your funds", c: "Because seed phrases expire quickly", d: "Because it's illegal to share them" }, correctAnswer: "b", explanation: "Your seed phrase IS your wallet. Anyone who has those 12 or 24 words can access and drain all your crypto from any compatible wallet app. No legitimate service — no exchange, no support team, no developer — will ever ask for your seed phrase.", difficulty: "easy", xpReward: 10 },
    { id: 83, moduleId: "scams", question: "What is 'imposter syndrome' in the context of crypto scams?", options: { a: "Feeling like you're not good enough to invest", b: "When scammers impersonate well-known figures or companies to lend credibility to their scheme", c: "A psychological condition of investors", d: "When a legitimate project impersonates another" }, correctAnswer: "b", explanation: "Scammers create fake social media accounts, websites, and emails that look like they're from Elon Musk, Binance support, or the SEC. They use this false authority to promote fake giveaways, investments, or 'security updates' that steal your crypto.", difficulty: "medium", xpReward: 20 },
    { id: 84, moduleId: "scams", question: "What should you do if you suspect you've fallen for a crypto scam?", options: { a: "Send more money to try to recover your losses", b: "Report it to the platform, relevant authorities, and warn others — and move on without sending more money", c: "Delete all evidence immediately", d: "Try to hack the scammer back" }, correctAnswer: "b", explanation: "If scammed: stop sending money immediately, report to the exchange/platform used, file a report with law enforcement (like the FBI's IC3 in the US), document everything, and warn others. Recovery is rarely possible, so prevention is key.", difficulty: "easy", xpReward: 10 },
    { id: 85, moduleId: "scams", question: "What is the safest way to store large amounts of cryptocurrency?", options: { a: "On an exchange", b: "In a hardware wallet (cold storage) with your seed phrase backed up securely offline", c: "In a hot wallet on your phone", d: "In a shared online account" }, correctAnswer: "b", explanation: "Hardware wallets like Trezor or Ledger store private keys offline, making them immune to online attacks. Combined with a seed phrase stored in a fireproof safe or engraved on metal, this provides the highest level of security for significant holdings.", difficulty: "easy", xpReward: 10 },

    // ══════════════════════════════════════════════
    //  MODULE: INVESTING (17 questions)
    // ══════════════════════════════════════════════
    { id: 86, moduleId: "investing", question: "What is the relationship between risk and reward in investing?", options: { a: "Higher risk always leads to higher returns", b: "Generally, investments with higher potential returns also carry higher risk of loss", c: "Risk and reward are unrelated", d: "Lower risk always means lower returns" }, correctAnswer: "b", explanation: "This is a fundamental investing principle. High-risk investments (like small altcoins) can produce huge gains or total losses. Low-risk investments (like stablecoins) offer modest but more predictable returns. The key is finding the right balance for your situation.", difficulty: "easy", xpReward: 10 },
    { id: 87, moduleId: "investing", question: "What is diversification and why does it matter?", options: { a: "Putting all your money into one asset", b: "Spreading investments across different assets to reduce overall risk", c: "Only investing in Bitcoin", d: "Switching investments every day" }, correctAnswer: "b", explanation: "Diversification means not putting all your eggs in one basket. If you hold only one coin and it crashes, you lose everything. By holding multiple assets (Bitcoin, Ethereum, stablecoins), poor performance in one can be offset by others.", difficulty: "easy", xpReward: 10 },
    { id: 88, moduleId: "investing", question: "What does 'long-term investing' mean in the context of crypto?", options: { a: "Holding investments for multiple days", b: "Holding investments for months or years, regardless of short-term price fluctuations", c: "Only investing in old cryptocurrencies", d: "Investing in companies that have been around a long time" }, correctAnswer: "b", explanation: "Long-term investors ('HODLers') buy assets they believe in and hold through market cycles. Historically, long-term holding has been the most successful strategy in crypto — despite extreme volatility, Bitcoin's long-term trend has been upward.", difficulty: "easy", xpReward: 10 },
    { id: 89, moduleId: "investing", question: "How can emotions negatively impact investment decisions?", options: { a: "They can't — emotions are always helpful", b: "Fear can cause panic selling at losses; greed can cause buying at peaks; both lead to poor timing", c: "Emotions only affect stock investors", d: "Emotions make investing more fun, so they're good" }, correctAnswer: "b", explanation: "Emotional investing is one of the biggest wealth destroyers. Fear during crashes leads to selling at the bottom. Greed during rallies leads to buying at the top. Developing a strategy and sticking to it helps overcome emotional impulses.", difficulty: "medium", xpReward: 20 },
    { id: 90, moduleId: "investing", question: "What is FOMO investing and why should you avoid it?", options: { a: "A smart investment strategy", b: "Buying an asset impulsively because everyone else seems to be profiting — often leading to buying at peak prices", c: "A way to research investments", d: "A form of dollar-cost averaging" }, correctAnswer: "b", explanation: "FOMO (Fear Of Missing Out) drives people to buy at the worst times — when prices have already skyrocketed and are about to correct. The best investors buy when others are fearful and sell when others are greedy, which requires emotional discipline.", difficulty: "medium", xpReward: 20 },
    { id: 91, moduleId: "investing", question: "What are 'market cycles' in cryptocurrency?", options: { a: "When the market opens and closes each day", b: "Recurring patterns of expansion (bull markets) and contraction (bear markets)", c: "When Bitcoin mining rewards change", d: "Seasonal changes in trading volume" }, correctAnswer: "b", explanation: "Crypto markets tend to cycle through phases: accumulation (smart money buys), uptrend (prices rise, public gets interested), distribution (early investors sell), and downtrend (prices fall, public loses interest). Understanding cycles helps with long-term planning.", difficulty: "medium", xpReward: 20 },
    { id: 92, moduleId: "investing", question: "What is 'dollar-cost averaging' (DCA) and what is its main benefit?", options: { a: "Buying all at once at the lowest price", b: "Investing a fixed amount regularly, reducing the risk of making a large purchase at the wrong time", c: "Averaging the prices of different cryptocurrencies", d: "Converting dollars to euros" }, correctAnswer: "b", explanation: "DCA removes the stress of trying to time the market. By investing $100 every week regardless of price, you buy more when prices are low and less when they're high. Over time, this typically results in a better average purchase price.", difficulty: "easy", xpReward: 10 },
    { id: 93, moduleId: "investing", question: "How does inflation relate to cryptocurrency investment?", options: { a: "Cryptocurrency is immune to inflation effects", b: "Some investors see Bitcoin as a hedge against inflation since it has a fixed supply, unlike fiat currencies that can be printed", c: "Inflation has no effect on any type of investment", d: "Inflation makes cryptocurrency worth less" }, correctAnswer: "b", explanation: "When governments print more money, each unit becomes less valuable (inflation). Since Bitcoin has a fixed supply of 21 million coins, some investors view it as 'digital gold' — a store of value that can't be debased. However, Bitcoin's short history makes this theory still debated.", difficulty: "hard", xpReward: 30 },
    { id: 94, moduleId: "investing", question: "What does 'portfolio rebalancing' mean?", options: { a: "Starting a completely new portfolio", b: "Periodically adjusting your holdings to maintain your desired asset allocation percentages", c: "Selling everything and starting over", d: "Adding more of your best-performing asset" }, correctAnswer: "b", explanation: "If your target is 50% BTC and 50% ETH, but BTC's growth makes it 70% of your portfolio, you'd sell some BTC and buy ETH to rebalance. This automatically enforces 'buy low, sell high' and maintains your risk profile.", difficulty: "hard", xpReward: 30 },
    { id: 95, moduleId: "investing", question: "Why is it important to only invest money you can afford to lose?", options: { a: "Because cryptocurrency is guaranteed to lose value", b: "Because crypto is volatile and you shouldn't risk money needed for essentials like rent, food, or education", c: "Because the government will take it anyway", d: "Because investing is basically gambling" }, correctAnswer: "b", explanation: "Cryptocurrency prices can drop 50-80% in bear markets. If you invest your rent money and the market crashes, you could lose your home. Only invest disposable income — money you won't need in the near term — into high-risk assets.", difficulty: "easy", xpReward: 10 },
    { id: 96, moduleId: "investing", question: "What is a 'stablecoin' and what role does it play in an investment portfolio?", options: { a: "A coin that never changes in value", b: "A cryptocurrency pegged to a stable asset like the US dollar, useful for preserving value during volatility", c: "A coin that's always going up", d: "A type of government bond" }, correctAnswer: "b", explanation: "Stablecoins like USDC and USDT maintain a ~$1 value by being backed by reserves. They're useful for parking profits during market downturns, moving funds between exchanges, and as a low-risk component of a crypto portfolio.", difficulty: "medium", xpReward: 20 },
    { id: 97, moduleId: "investing", question: "What is 'opportunity cost' in investing?", options: { a: "The cost of a trading opportunity", b: "The potential gain you give up by choosing one investment over another", c: "The fee charged by exchanges", d: "The cost of missing a trade" }, correctAnswer: "b", explanation: "If you invest $1,000 in a coin that gains 10%, but another coin gained 50% in the same period, your opportunity cost is the 40% difference. This concept helps you evaluate whether your capital is deployed in the best possible way.", difficulty: "hard", xpReward: 30 },
    { id: 98, moduleId: "investing", question: "What is the difference between saving and investing?", options: { a: "They are the same thing", b: "Saving preserves money with minimal risk; investing aims to grow money by accepting some level of risk", c: "Saving is riskier than investing", d: "Investing is only for wealthy people" }, correctAnswer: "b", explanation: "Saving in a bank account preserves your money but often loses value to inflation over time. Investing accepts risk for the potential of higher returns. A good strategy often includes both: an emergency fund in savings plus investments for long-term growth.", difficulty: "easy", xpReward: 10 },
    { id: 99, moduleId: "investing", question: "What does 'time in the market beats timing the market' mean?", options: { a: "You should check prices every hour", b: "Staying invested for the long term generally outperforms trying to predict the perfect moments to buy and sell", c: "The market is only open during business hours", d: "You should sell before going to sleep" }, correctAnswer: "b", explanation: "Studies consistently show that trying to perfectly time buys and sells usually results in worse performance than simply staying invested. Missing just the 10 best days in a decade can cut your returns dramatically. Patience and consistency win.", difficulty: "medium", xpReward: 20 },
    { id: 100, moduleId: "investing", question: "What is 'yield farming' and what risk does it carry?", options: { a: "Growing crops and selling them for crypto", b: "Lending or staking crypto in DeFi protocols to earn rewards — but with risks like smart contract bugs and impermanent loss", c: "A guaranteed way to earn passive income", d: "A type of mining" }, correctAnswer: "b", explanation: "Yield farming involves providing liquidity to DeFi protocols in exchange for token rewards. While APYs can look impressive, risks include smart contract vulnerabilities, impermanent loss (when the paired assets change in relative value), and token price drops.", difficulty: "hard", xpReward: 30 },
    { id: 101, moduleId: "investing", question: "Why should teenagers be especially careful with crypto investing?", options: { a: "Because they're not smart enough", b: "Because they may have limited funds, less financial experience, and more years ahead where losses could impact their future", c: "Because crypto is illegal for teens", d: "Because they don't understand technology" }, correctAnswer: "b", explanation: "Teens often have limited income from part-time jobs or allowances. Losing significant money to a scam or market crash could impact their ability to save for college, a car, or other goals. Start small, focus on learning, and never invest money you can't afford to lose.", difficulty: "easy", xpReward: 10 },
    { id: 102, moduleId: "investing", question: "What is a good first step before making any crypto investment?", options: { a: "Borrowing money to invest more", b: "Educating yourself thoroughly, setting clear goals, and establishing a budget you're comfortable with", c: "Asking social media for the best coin to buy", d: "Investing your entire savings immediately" }, correctAnswer: "b", explanation: "Education is the best investment you can make. Before risking any money, understand blockchain basics, different cryptocurrencies, risk management, and common scams. Set clear goals (e.g., 'learn and invest $50/month for 5 years') and never invest money you need.", difficulty: "easy", xpReward: 10 }
  ];
})();